async function registerOAuthClient(params) {
  const {
    serverUrl,
    redirectUri,
    clientName = "vSync Obsidian Plugin"
  } = params;
  const baseUrl = serverUrl.replace(/\/$/, "");
  const registerUrl = `${baseUrl}/oauth/register`;
  const body = JSON.stringify({
    redirect_uris: [redirectUri],
    client_name: clientName
  });
  try {
    const response = await fetch(registerUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body
    });
    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      const { error, error_description } = errorData;
      if (error === "invalid_redirect_uri") {
        throw new Error(`\uC798\uBABB\uB41C \uB9AC\uB2E4\uC774\uB809\uD2B8 URI\uC785\uB2C8\uB2E4: ${error_description || "unknown"}`);
      }
      throw new Error(`Client registration failed: HTTP ${response.status}`);
    }
    const data = await response.json();
    return {
      clientId: data.client_id
    };
  } catch (error) {
    if (error instanceof TypeError) {
      throw new Error("Network error during client registration");
    }
    throw error;
  }
}

